import{_ as t,o as a,c as o,a4 as n}from"./chunks/framework.BybBnFXO.js";const m=JSON.parse(`{"title":"Chatoyancy (Cat's-Eye Effect)","description":"","frontmatter":{"title":"Chatoyancy (Cat's-Eye Effect)","phenomenon":"chatoyancy"},"headers":[],"relativePath":"optical-phenomena/chatoyancy.md","filePath":"optical-phenomena/chatoyancy.md","lastUpdated":1784176423000}`),r={name:"optical-phenomena/chatoyancy.md"};function i(s,e,c,l,d,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="chatoyancy-cat-s-eye-effect" tabindex="-1">Chatoyancy (Cat&#39;s-Eye Effect) <a class="header-anchor" href="#chatoyancy-cat-s-eye-effect" aria-label="Permalink to &quot;Chatoyancy (Cat&#39;s-Eye Effect)&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Chatoyancy appears when a gem contains densely packed parallel fibers, channels, or tubes. On a cabochon cut perpendicular to the inclusions, a single bright band slides across the dome — the &quot;cat&#39;s eye.&quot; The namesake is chrysoberyl (cymophane); the same effect occurs in tourmaline, apatite, and others. Moonstone produces a visually similar floating sheen via a different mechanism (see adularescence).</p><h2 id="mechanism" tabindex="-1">Mechanism <a class="header-anchor" href="#mechanism" aria-label="Permalink to &quot;Mechanism&quot;">​</a></h2><p>Single-direction reflection: all inclusions align along one direction (e.g., hollow tubes parallel to the c-axis in chrysoberyl). From above, each tube reflects perpendicular light to the viewer. The collective reflection is geometrically constrained to a narrow band perpendicular to the inclusion direction. Effect strength scales with inclusion density, fineness, and parallelism.</p><h2 id="example-gemstones" tabindex="-1">Example Gemstones <a class="header-anchor" href="#example-gemstones" aria-label="Permalink to &quot;Example Gemstones&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gem</th><th>Tubes/Fibers</th><th>Host</th></tr></thead><tbody><tr><td>Chrysoberyl Cat&#39;s-eye / 金绿猫眼</td><td>hollow tubes along c-axis</td><td>Chrysoberyl</td></tr><tr><td>Tourmaline Cat&#39;s-eye / 碧玺猫眼</td><td>parallel hollow channels</td><td>Elbaite</td></tr><tr><td>Apatite Cat&#39;s-eye / 磷灰石猫眼</td><td>fibrous inclusions</td><td>Apatite</td></tr><tr><td>Hawk&#39;s-eye / 鹰眼石</td><td>crocidolite fibers</td><td>Quartz (pseudomorph)</td></tr><tr><td>Tiger&#39;s-eye / 虎眼石</td><td>crocidolite fibers (oxidized)</td><td>Quartz (pseudomorph)</td></tr></tbody></table><p><em>See the <a href="./intro.html">optical phenomena overview</a>.</em></p>',8)])])}const y=t(r,[["render",i]]);export{m as __pageData,y as default};
